let state_code;
let error_mask = 0;
const v = msg.payload.d;

// 1. Luôn tính toán error_mask độc lập để thống kê
if (v[12].value)      error_mask += 1;
if (v[13].value)      error_mask += 2;
if (v[14].value)      error_mask += 4;
if (v[15].value)      error_mask += 8;
if (v[16].value)      error_mask += 16;

// 2. Xác định state_code ưu tiên ĐÈN XANH (theo ý bạn)
if (v[9].value) {
    state_code = 1; // Ưu tiên hiển thị Xanh
} else if (v[10].value) {
    state_code = 2; // Ưu tiên hiển thị Vàng
} else if (v[11].value || error_mask > 0) {
    state_code = 3; // Chỉ hiện Đỏ khi không Xanh/Vàng mà có lỗi
} else {
    state_code = -1;
}

// 3. Đóng gói dữ liệu để gửi lên InfluxDB
msg.payload = [
    {
        state_code: state_code,      // Biến này để làm màu sắc Dashboard (Xanh/Vàng)
        error_mask: error_mask,      // Biến này ĐỘC LẬP để vẽ biểu đồ tròn lỗi
        has_error: error_mask > 0 ? 1 : 0 // Cờ báo hiệu có lỗi tiềm ẩn
    },
    {
        factory: 'Bông Bạch Tuyết Vĩnh Lộc',
        system: 'Công đoạn thành phẩm',
        machine: 'MMTB178',
        device: 'ECU1051-PLCMITSU',
        error_mask: error_mask
    }
];

return msg;

